import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useJobs } from '../context/JobContext';
import AnimatedCard from '../components/AnimatedCard';
import StatsCard from '../components/StatsCard';
import ImportExport from '../components/ImportExport';
import EmptyState from '../components/EmptyState';
import { FaSearch, FaFilter, FaBriefcase, FaCalendarCheck, FaClock, FaCheckCircle, FaTimesCircle, FaLink } from 'react-icons/fa';

function Dashboard() {
  const { jobs, deleteJob, getStats, loading } = useJobs();
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('All');
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const statuses = ['All', 'Applied', 'Interviewing', 'Offer', 'Rejected'];
  const stats = getStats();

  const filteredJobs = jobs.filter(job => {
    const matchesSearch = job.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         job.position.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = filterStatus === 'All' || job.status === filterStatus;
    return matchesSearch && matchesStatus;
  });

  const statCards = [
    { icon: <FaBriefcase />, label: 'Total Applications', value: stats.total, color: 'from-purple-500 to-purple-700', bgColor: 'from-purple-500 to-purple-700' },
    { icon: <FaClock />, label: 'Applied', value: stats.applied, color: 'from-blue-500 to-blue-700', bgColor: 'from-blue-500 to-blue-700' },
    { icon: <FaCalendarCheck />, label: 'Interviewing', value: stats.interviewing, color: 'from-yellow-500 to-yellow-700', bgColor: 'from-yellow-500 to-yellow-700' },
    { icon: <FaCheckCircle />, label: 'Offers', value: stats.offer, color: 'from-green-500 to-green-700', bgColor: 'from-green-500 to-green-700' },
    { icon: <FaTimesCircle />, label: 'Rejected', value: stats.rejected, color: 'from-red-500 to-red-700', bgColor: 'from-red-500 to-red-700' },
    { icon: <FaLink />, label: 'With Links', value: stats.hasLink, color: 'from-teal-500 to-teal-700', bgColor: 'from-teal-500 to-teal-700' }
  ];

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-purple-50 to-blue-50 flex items-center justify-center">
        <motion.div
          animate={{ rotate: 360 }}
          transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
          className="w-16 h-16 border-4 border-purple-200 border-t-purple-600 rounded-full"
        />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-purple-50 via-white to-blue-50">
      <div className="container mx-auto px-4 py-8">
        {/* Header with Animation */}
        <motion.div
          initial={{ y: -50, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ type: "spring", stiffness: 100 }}
          className="mb-8 text-center"
        >
           <h1 className="text-4xl md:text-5xl font-bold text-[#097c7f] mb-2">
    Job Applications Dashboard
  </h1>
          <p className="text-gray-600">Track and manage your job search journey</p>
        </motion.div>

        {/* Import/Export with Animation */}
        <motion.div
          initial={{ x: -50, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          transition={{ delay: 0.2 }}
        >
          <ImportExport />
        </motion.div>

        {/* Stats Grid */}
        <motion.div 
          className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-8"
          variants={{
            hidden: { opacity: 0 },
            show: {
              opacity: 1,
              transition: { staggerChildren: 0.1 }
            }
          }}
          initial="hidden"
          animate="show"
        >
          {statCards.map((stat, index) => (
            <motion.div
              key={index}
              variants={{
                hidden: { y: 20, opacity: 0 },
                show: { y: 0, opacity: 1 }
              }}
            >
              <StatsCard {...stat} />
            </motion.div>
          ))}
        </motion.div>

        {/* Search and Filter */}
        <motion.div
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.4 }}
          className="bg-white/80 backdrop-blur-sm rounded-xl shadow-lg p-4 mb-8"
        >
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1 relative">
              <FaSearch className="absolute left-3 top-3 text-gray-400" />
              <input
                type="text"
                placeholder="Search by company or position..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent"
              />
            </div>
            
            <div className="relative">
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => setIsFilterOpen(!isFilterOpen)}
                className="w-full md:w-auto px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition flex items-center gap-2 justify-center"
              >
                <FaFilter />
                Filter by Status
              </motion.button>
              
              <AnimatePresence>
                {isFilterOpen && (
                  <motion.div
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                    className="absolute z-10 mt-2 w-full bg-white rounded-lg shadow-xl border border-gray-100 overflow-hidden"
                  >
                    {statuses.map(status => (
                      <motion.button
                        key={status}
                        whileHover={{ x: 5 }}
                        onClick={() => {
                          setFilterStatus(status);
                          setIsFilterOpen(false);
                        }}
                        className={`w-full px-4 py-2 text-left hover:bg-purple-50 transition ${
                          filterStatus === status ? 'bg-purple-100 text-purple-600 font-semibold' : ''
                        }`}
                      >
                        {status}
                      </motion.button>
                    ))}
                  </motion.div>
                )}
              </AnimatePresence>
            </div>
          </div>
        </motion.div>

        {/* Job Cards Grid */}
        {filteredJobs.length === 0 ? (
          <EmptyState />
        ) : (
          <motion.div 
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
            variants={{
              hidden: { opacity: 0 },
              show: {
                opacity: 1,
                transition: { staggerChildren: 0.1 }
              }
            }}
            initial="hidden"
            animate="show"
          >
            {filteredJobs.map((job, index) => (
              <AnimatedCard 
                key={job.id} 
                job={job} 
                onDelete={deleteJob}
                index={index}
              />
            ))}
          </motion.div>
        )}
      </div>
    </div>
  );
}

export default Dashboard;
